+import XCTest
+@testable import GhostPepper
+
+@MainActor
+final class ShortcutCaptureMonitorControllerTests: XCTestCase {
+    func testBeginAndEndCaptureSuspendAndResumeTheHotkeyMonitor() {
+        let hotkeyMonitor = RecordingShortcutCaptureHotkeyMonitor()
+        let controller = ShortcutCaptureMonitorController(hotkeyMonitor: hotkeyMonitor)
+
+        controller.beginCapture()
+        controller.endCapture()
+
+        XCTAssertEqual(hotkeyMonitor.events, [.suspend, .resume])
+    }
+}
+
+private final class RecordingShortcutCaptureHotkeyMonitor: HotkeyMonitoring {
+    enum Event: Equatable {
+        case suspend
+        case resume
+    }
+
+    var isRunning = false
+    private(set) var events: [Event] = []
+
+    func start(bindings: HotkeyBindings, effectHandler: @escaping HotkeyEffectHandler) throws {
+        _ = bindings
+        _ = effectHandler
+    }
+
+    func suspend() {
+        events.append(.suspend)
+    }
+
+    func resume() {
+        events.append(.resume)
+    }
+
+    func stop() {
+    }
+}
